local LMapBase = LMapBase
---@class LWonderlandMap:LMapBase
local LWonderlandMap = LxClass("LWonderlandMap",LMapBase)

-----------------------------------------------------------------
local typeSpriteRenderer = typeof(UnityEngine.SpriteRenderer)
local typeofYXIMapCamera =  typeof(CardEHT.YXIMapCamera)

local YXTouchManager = CS.YXTouchManager


-----------------------------------------------------------------
function LWonderlandMap:LWonderlandMap()

end

function LWonderlandMap:OnDestroy()
    if self._objPool then
        self._objPool:Destroy()
        self._objPool = nil
    end

    if self._seqCom then
        self._seqCom:Destroy()
        self._seqCom = nil
    end

    if gLGpManager then
        gLGpManager:FindWonderlandCopyGp():ClearWhenExit()
    end

    self:RemoveTouchEvent()
    --self:ReleaseMapEvent()
    LMapBase.OnDestroy(self)
end

function LWonderlandMap:OnCreate()
    LMapBase.OnCreate(self)

    self._seqCom = SequenceCom:New()
end

function LWonderlandMap:OnResetMap()
    local mapName = "MapWonderland"
    self:SetMapName(mapName)

    self:DelayGuideReadyMsg()
end


function LWonderlandMap:OnExitMap()
    if gLGpManager then
        gLGpManager:FindWonderlandCopyGp():ClearWhenExit()
    end
    if self._objPool then
        self._objPool:ReturnAllObj()
    end

    self:RemoveTouchEvent()
    self:ReleaseMapEvent()
end

function LWonderlandMap:CheckNeedChange()
    return false
end

function LWonderlandMap:IsCheckClear()
    return true
end

