function LWonderlandMap:OnEnterMap()

    --self:DelayGuideReadyMsg()
    self:RegisterMapEvent()
    self:InitTouchEvent()
    local mapTran = self._mapTrans

    self._isFirst = self:GetMapArg("isFirst")
    local themeId = gModelWonderland:GetThemeId()
    local themeCfg = gModelWonderland:GetThemeConfig(themeId)
    if not themeCfg then
        return
    end
    local bgPath= themeCfg.pic
    local paths = string.split(bgPath,",")


    local layerRoot = CS.FindTrans(mapTran,"LayerRoot")
    local LayerBg = CS.FindTrans(layerRoot,"LayerBg")
    local bg_1 = CS.FindTrans(LayerBg,"bg_1")
    local bg_2 = CS.FindTrans(LayerBg,"bg_2")
    local bg_3 = CS.FindTrans(LayerBg,"bg_3")

    local dataList =
    {
        {trans = bg_1,spriteName = paths[1]},
        {trans = bg_2,spriteName = paths[2]},
        {trans = bg_3,spriteName = paths[3]},

    }
    CS.ShowObject(layerRoot,false)
    self:SetSpriteList(dataList,function ()
        if not CS.IsValidObject(layerRoot) then
            return
        end
        CS.ShowObject(layerRoot,true)
    end)


    local layerDis = 0.8
    local gridDis = 1.5

    if not self._objPool then
        self._objPool = UIObjPool:New()
        local templateRoot= CS.FindTrans(layerRoot,"TemplateRoot")
        local template = CS.FindTrans(templateRoot,"GridTemplate")
        self._objPool:Create(templateRoot,template)
    end


    self._gridList ={}
    local layerDatas = gModelWonderland:GetLayerInfo()
    local itemRoot = CS.FindTrans(layerRoot,"GridRoot")
    local cnt = #layerDatas
    for k= 1,cnt do
        local layerdata = layerDatas[k]
        local gridCnt = #layerdata.grids
        for j = 1,gridCnt do
            local gridData = layerdata.grids[j]
            local gridIndex = gridData:GetGridIndex()
            local layerIndex = gridData:GetLayerIndex()
            local itemNew = self._objPool:GetObj()
            itemNew.transform:SetParent(itemRoot.transform, false)
            itemNew.name = string.format("item{%s_%s}",layerIndex,gridIndex)
            CS.ShowObject(itemNew, true)



            local posX = (gridIndex - (gridCnt-1)/2) * gridDis
            local posY = layerIndex*layerDis -2
            itemNew.transform.localPosition = Vector3.New(posX,posY,0)

            local gridKey = gModelWonderland:FormatGridKey(layerIndex,gridIndex)
            self._gridList[gridKey] = {gridKey = gridKey,item = itemNew.transform,itemdata = gridData}
        end
    end


    
    gLGpManager:FindWonderlandCopyGp():InitCtrl(self)
    local isInMap = gModelWonderland:IsInMap()
    if isInMap then
        gLGpManager:FindWonderlandCopyGp():RefreshGrid(self._isFirst)
        self._isFirst = false
        self:RefreshGridState()
        self:InitCamPos()
    end

end

function LWonderlandMap:RegisterMapEvent()
    self._refreshFunc = function()
        gLGpManager:FindWonderlandCopyGp():RefreshGrid(self._isFirst)
        self._isFirst = false
        gLGpManager:FindWonderlandCopyGp():RefreshRolePos()
    end

    self._onTargetClose= function(wndName)
        gLGpManager:FindWonderlandCopyGp():RefreshRolePos()
    end

    --self._onTargetOpen = function(wndName)
    --    if waitWndList[wndName] then
    --        gLGpManager:FindWonderlandCopyGp():SetWaitMoveTag()
    --    end
    --end

    --self._waitByEvent = function()
    --    self:WaitByEvent()
    --end

    self._onOperRet = function(...)
        self:OnOperRet(...)
    end

    self._followKelaken = function()
        local tran = gLGpManager:FindWonderlandCopyGp():GetKelakenTran()
        if tran then
            self:FollowRole(tran,Vector3.zero,0.2)
        else
            gLGpManager:FindWonderlandCopyGp():SetKelakenFollow()
        end
    end

    self._showHud = function(...)
        gLGpManager:FindWonderlandCopyGp():ShowHud(...)
    end


    self:MapEventRecv(EventNames.ON_WONDERLAND_PAGE_CHANGE,self._refreshFunc)
    self:MapEventRecv(EventNames.ON_WONDERLAND_OPER_RET,self._onOperRet)
    --self:MapEventRecv(EventNames.ON_WONDERLAND_OPER_WAIT,self._waitByEvent)
    self:MapEventRecv(EventNames.ON_WND_CLOSE,self._onTargetClose)
    --self:MapEventRecv(EventNames.ON_WND_FINISH,self._onTargetOpen)
    self:MapEventRecv(EventNames.ON_FOLLOW_KELAKEN,self._followKelaken)
    self:MapEventRecv(EventNames.ON_SHOW_WONDER_HUD,self._showHud)
end

function LWonderlandMap:ReleaseMapEvent()
    self:MapEventRemove(EventNames.ON_WONDERLAND_PAGE_CHANGE,self._refreshFunc)
    self:MapEventRemove(EventNames.ON_WONDERLAND_OPER_RET,self._onOperRet)
    --self:MapEventRemove(EventNames.ON_WONDERLAND_OPER_WAIT,self._waitByEvent)
    self:MapEventRemove(EventNames.ON_WND_CLOSE,self._onTargetClose)
    --self:MapEventRemove(EventNames.ON_WND_FINISH,self._onTargetOpen)
    self:MapEventRemove(EventNames.ON_FOLLOW_KELAKEN,self._followKelaken)
    self:MapEventRemove(EventNames.ON_SHOW_WONDER_HUD,self._showHud)
end

function LWonderlandMap:GetGridList()
    return self._gridList
end

function LWonderlandMap:RefreshGridState()
    gLGpManager:FindWonderlandCopyGp():RefreshGridState()
end

function LWonderlandMap:ShowWaitEffect()
    local eventType = self._waitEvent
    self._waitEvent = nil
    if eventType == ModelWonderland.EVENT_POD then

        local seq = self._seqCom:CreateSeq("delayPlayEff")
        seq:AppendInterval(0.5)
        seq:AppendCallback(function ()
            gLGpManager:FindWonderlandCopyGp():PlayBehit(40003)
        end)
        seq:AppendInterval(0.33)
        seq:OnComplete(function ()
            self._seqCom:DeleteSeq("delayPlayEff")
            gLGpManager:FindWonderlandCopyGp():RefreshRolePos()
        end)
        seq:PlayForward()


    elseif eventType == ModelWonderland.EVENT_BEAN_VINE then
        local seq = self._seqCom:CreateSeq("delayPlayEff")
        seq:AppendInterval(0.2)
        seq:OnComplete(function ()
            self._seqCom:DeleteSeq("delayPlayEff")
            gLGpManager:FindWonderlandCopyGp():RefreshRolePos()
        end)
        seq:PlayForward()
    else
        gLGpManager:FindWonderlandCopyGp():RefreshRolePos()
    end
end

function LWonderlandMap:OnOperRet(type,grid)
    if type == ModelWonderland.EVENT_WORLD_LEAVES then
        FireEvent(EventNames.ON_WONDER_GRID_CLICK,grid.layerIndex,grid.gridIndex)
    end
end

function LWonderlandMap:WaitByEvent(type)

    local wnd = GF.FindFirstWndByName("UIAward")
    if  wnd then
        self._waitEvent = type
        return
    end

    self:ShowWaitEffect()
end


function LWonderlandMap:SetSprite(trans,spriteName,endFunc)
    self:SetSpriteRenderer(trans, spriteName, endFunc)
end

function LWonderlandMap:SetSpriteList(dataList,endFunc)
    local cnt = #dataList
    for k,v in ipairs(dataList) do
        local trans = v.trans
        local spriteName = v.spriteName
        self:SetSprite(trans,spriteName,function ()
            cnt=cnt-1
            if cnt ==0 then
                if endFunc then
                    endFunc()
                end
            end
        end)
    end
end

function LWonderlandMap:InitTouchEvent()
    local op = LGameTouch.TOUCH_WONDER
    gLGameTouch:TouchRegister(op,LGameTouch.TOUCH_EVT_START,function (screenPos)
        if self:IsOverUI(screenPos) then
            return
        end

        self._touchStart = true
    end)

    gLGameTouch:TouchRegister(op,LGameTouch.TOUCH_EVT_MOVE,function (screenPos)
        if not self._touchStart then
            return
        end
        if self:IsOverUI(screenPos) then
            return
        end
        self:OnDragBegin(screenPos)
        self:OnDrag(screenPos)
    end)

    gLGameTouch:TouchRegister(op,LGameTouch.TOUCH_EVT_END,function (screenPos)
        if not self._touchStart then
            return
        end
        if self:IsOverUI(screenPos) then
            return
        end
        self:OnDragEnd()
        self._touchStart = false
    end)

    gLGameTouch:TouchRegister(op,LGameTouch.TOUCH_EVT_CANCEL,function (screenPos)
        if not self._touchStart then
            return
        end
        if self:IsOverUI(screenPos) then
            return
        end
        self:OnDragEnd()
        self._touchStart = false

    end)
end

function LWonderlandMap:IsOverUI(screenPos)
    local touchObject = YXTouchManager.EventSystemRaycastGameObject(screenPos)
    if touchObject and gLGameUI:IsUILayer(touchObject.layer)  then
        return true
    end
end

function LWonderlandMap:RemoveTouchEvent()
    if gLGameTouch then gLGameTouch:TouchUnRegister(LGameTouch.TOUCH_WONDER) end
end

function LWonderlandMap:OnDragBegin(mousePos)
    if self._isMoving then
        return
    end
    self._isMoving = true
    local pos = gLGameScene:GetCurrentSceneCamera().transform.position
    self._cameraStartPos = pos
    self._startMousePos = mousePos

    if self._mapCameraCom then
        self._mapCameraCom:StartDrag()
    end
end

function LWonderlandMap:OnDragEnd()
    if not self._isMoving then
        return
    end
    self._isMoving = false
    self._mapCameraCom:EndDrag()
end

function LWonderlandMap:OnDrag(mousePos)
    if not self._isMoving then
        return
    end
    if not self._mapCameraCom then
        return
    end

    local offset = self._startMousePos - mousePos
    local offsetY = offset.y* 0.01 + self._cameraStartPos.y
    self._mapCameraCom:ChangeCameraPos(Vector3.New(0,offsetY,0))
end

function LWonderlandMap:FollowRole(transform,offset,time)
    if self._mapCameraCom then
        self._mapCameraCom:StartFollowState(transform,offset,time)
    end
end

function LWonderlandMap:InitCamPos()
    local curLayer = gModelWonderland:GetCurLayer()
    local curGrid = gModelWonderland:GetCurGrid()
    local gridKey = gModelWonderland:FormatGridKey(curLayer,curGrid)
    local item = self._gridList[gridKey].item
    local pos = item.transform.position + Vector3(0,0.8,0)
    self._mapCameraCom:ChangeCameraPos(pos)
end


-----------------------------------------------------------------
function LWonderlandMap:InitCameraComponent()
    local layerRoot = CS.FindTrans(self._mapTrans,"LayerRoot")
    local com = layerRoot:GetComponent(typeofYXIMapCamera)
    self._mapCameraCom = com

    local range = self:GetCameraRange()

    self._mapCameraCom:SetRange(Vector2.New(0,range.x),Vector2.New(0,range.y))
end

function LWonderlandMap:GetCameraRange()

    local orthgraphicSize,designOrthgraphicSize = LUtil.GetCameraSize()

    local min = orthgraphicSize - designOrthgraphicSize
    local max = 11.36+ designOrthgraphicSize - orthgraphicSize

    return Vector2.New(min,max)
end

function LWonderlandMap:UpdateMapVisible()
    if not self:IsMapValid() then
        return
    end


    LMapBase.UpdateMapVisible(self)
end


function LWonderlandMap:GetGridPos(layerIndex,gridIndex)
    local gridKey = gModelWonderland:FormatGridKey(layerIndex,gridIndex)
    local data = self._gridList and self._gridList[gridKey]
    if data then
        return data.item.position
    else
        return Vector3.zero
    end
end


-----------------------------------------------------------------

return LWonderlandMap
